import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as i,o,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Safety/cloudflare-api-token.md","filePath":"ta/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"ta/Safety/cloudflare-api-token.md"};function n(c,e,p,s,u,h){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Cloudflare API credentials, files மாறிய பிறகு Cloudflare CDN cache purge செய்ய ImgBed-க்கு உதவும்.</p><p><img src="'+a+'" alt="Cloudflare API Token settings" loading="lazy"></p><h2 id="எங்கு-configure-செய்வது" tabindex="-1">எங்கு Configure செய்வது <a class="header-anchor" href="#எங்கு-configure-செய்வது" aria-label="Permalink to &quot;எங்கு Configure செய்வது&quot;">​</a></h2><p>admin panel திறந்து செல்லவும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>நிரப்ப வேண்டியது:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="இந்த-setting-என்ன-செய்கிறது" tabindex="-1">இந்த Setting என்ன செய்கிறது <a class="header-anchor" href="#இந்த-setting-என்ன-செய்கிறது" aria-label="Permalink to &quot;இந்த Setting என்ன செய்கிறது&quot;">​</a></h2><p>Cloudflare public image URLs-ஐ cache செய்யலாம்.</p><p>Caching image delivery வேகமாக்கும். ஆனால் file delete, block, replace, அல்லது move செய்த பிறகும் பழைய content சில நேரம் தெரிந்துகொள்ளலாம்.</p><p>Cloudflare API credentials configure செய்த பிறகு, அந்த operations முடிந்ததும் ImgBed தொடர்புடைய Cloudflare cache-ஐ purge செய்ய முயலும்.</p><p>இது பயன்படும் சூழல்கள்:</p><ul><li>image delete செய்த பிறகு public link விரைவில் வேலை செய்யாமல் போக வேண்டும்.</li><li>image block செய்த பிறகு visitors original file பார்க்கக் கூடாது.</li><li>அதே பெயரில் file replace செய்தால் புதிய version விரைவில் தெரியும்.</li><li>files move/rename செய்தால் old path cache விரைவில் refresh ஆகும்.</li><li>public access rules மாற்றிய பிறகு public gallery அல்லது random image cache விரைவில் update ஆகும்.</li></ul><h2 id="காலியாக-விட்டால்-என்ன-ஆகும்" tabindex="-1">காலியாக விட்டால் என்ன ஆகும் <a class="header-anchor" href="#காலியாக-விட்டால்-என்ன-ஆகும்" aria-label="Permalink to &quot;காலியாக விட்டால் என்ன ஆகும்&quot;">​</a></h2><p>இந்த setting இல்லாமலும் ImgBed சாதாரணமாக இயங்கும்.</p><p>வித்தியாசம்: ImgBed actively Cloudflare CDN cache purge செய்யாது. visitors Cloudflare cache naturally expire ஆகும் வரை பழைய content பார்க்கலாம்.</p><h2 id="zone-id-எங்கு-கிடைக்கும்" tabindex="-1">Zone ID எங்கு கிடைக்கும் <a class="header-anchor" href="#zone-id-எங்கு-கிடைக்கும்" aria-label="Permalink to &quot;Zone ID எங்கு கிடைக்கும்&quot;">​</a></h2><p>Zone ID என்பது உங்கள் ImgBed domain பயன்படுத்தும் site-இன் Cloudflare Zone ID.</p><ol><li>Cloudflare dashboard-ல் sign in செய்யவும்.</li><li>உங்கள் ImgBed domain உள்ள site திறக்கவும்.</li><li>site overview page-ல் <code>Zone ID</code> கண்டறியவும்.</li><li>ImgBed <code>Zone ID</code> field-ல் copy செய்யவும்.</li></ol><p>இது site Zone ID; account ID அல்ல.</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>Cloudflare sign in செய்யும் email address உள்ளிடவும்.</p><p>கீழே கொடுக்கும் API Key-க்கு இது பொருந்த வேண்டும்.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Cloudflare Global API Key உள்ளிடவும்.</p><ol><li>Cloudflare dashboard-ல் sign in செய்யவும்.</li><li>profile திறக்கவும்.</li><li>API Tokens page-க்கு செல்லவும்.</li><li><code>Global API Key</code> கண்டறியவும்.</li><li>view செய்து copy செய்யவும்.</li><li>ImgBed <code>API Key</code> field-ல் paste செய்யவும்.</li></ol><p><img src="'+l+'" alt="View global API key" loading="lazy"></p><h2 id="எப்போது-effect-ஆகும்" tabindex="-1">எப்போது Effect ஆகும் <a class="header-anchor" href="#எப்போது-effect-ஆகும்" aria-label="Permalink to &quot;எப்போது Effect ஆகும்&quot;">​</a></h2><p>fields நிரப்பிய பிறகு settings save செய்யவும்.</p><p>இனிமேல் வரும் file changes Cloudflare cache purge செய்ய முயலும். பழைய operations retroactively purge ஆகாது. இதற்கு முன் file delete/replace செய்திருந்தால் Cloudflare cache expire ஆக காத்திருக்கவும் அல்லது Cloudflare-ல் manual purge செய்யவும்.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="இது-required-ஆ" tabindex="-1">இது Required ஆ? <a class="header-anchor" href="#இது-required-ஆ" aria-label="Permalink to &quot;இது Required ஆ?&quot;">​</a></h3><p>இல்லை.</p><p>உங்கள் domain Cloudflare பயன்படுத்தவில்லை என்றால், அல்லது CDN cache delay பிரச்சினை இல்லை என்றால் காலியாக விடலாம்.</p><h3 id="wrong-credentials-uploads-ஐ-பாதிக்குமா" tabindex="-1">Wrong Credentials Uploads-ஐ பாதிக்குமா? <a class="header-anchor" href="#wrong-credentials-uploads-ஐ-பாதிக்குமா" aria-label="Permalink to &quot;Wrong Credentials Uploads-ஐ பாதிக்குமா?&quot;">​</a></h3><p>பொதுவாக இல்லை.</p><p>wrong credentials ImgBed Cloudflare cache purge செய்யாமல் தடுக்கும். upload மற்றும் normal file access வேலை செய்ய வேண்டும்.</p><h3 id="deleted-image-இன்னும்-ஏன்-திறக்கிறது" tabindex="-1">Deleted Image இன்னும் ஏன் திறக்கிறது? <a class="header-anchor" href="#deleted-image-இன்னும்-ஏன்-திறக்கிறது" aria-label="Permalink to &quot;Deleted Image இன்னும் ஏன் திறக்கிறது?&quot;">​</a></h3><p>அதிகமான காரணம் Cloudflare பழைய file-ஐ cache செய்திருப்பது.</p><p>சரியான Cloudflare API credentials இருந்தால் file delete செய்யும்போது ImgBed தொடர்புடைய URL cache purge செய்யும்.</p><h3 id="file-replace-செய்த-பிறகும்-பழைய-image-ஏன்-தெரிகிறது" tabindex="-1">File Replace செய்த பிறகும் பழைய Image ஏன் தெரிகிறது? <a class="header-anchor" href="#file-replace-செய்த-பிறகும்-பழைய-image-ஏன்-தெரிகிறது" aria-label="Permalink to &quot;File Replace செய்த பிறகும் பழைய Image ஏன் தெரிகிறது?&quot;">​</a></h3><p>இதுவும் பொதுவாக CDN cache காரணமாகும்.</p><p>இந்த setting configured ஆன பிறகு same name file overwrite செய்யும்போது ImgBed old URL cache purge செய்ய முயலும்.</p>',44)])])}const b=i(d,[["render",n]]);export{I as __pageData,b as default};
